/// CredentialSanitizer removes sensitive information from strings.
/// This prevents stream keys, passwords, and other secrets from
/// appearing in crash reports, logs, or diagnostics.
struct CredentialSanitizer {

    /// The placeholder text that replaces redacted content
    static let redactedPlaceholder = "[REDACTED]"

    /// Sanitize a string by removing all known credential patterns
    static func sanitize(_ input: String) -> String {
        // Implementation should handle:
        // 1. RTMP URLs with embedded stream keys: rtmp://server/app/streamkey -> rtmp://server/app/[REDACTED]
        // 2. URLs with query parameters (key=xxx, token=xxx, password=xxx, secret=xxx, auth=xxx)
        // 3. URLs with userinfo (user:password@host)
        // 4. Generic patterns: "stream_key": "value", "password": "value", etc.
        // 5. Base64-encoded tokens that look like credentials
    }

    /// Sanitize all string values in a dictionary (for crash report fields)
    static func sanitizeDictionary(_ dict: [String: Any]) -> [String: Any] {
        // Recursively sanitize all string values
    }
}
```

The sanitizer should use regex patterns to find and replace:
- RTMP URL paths after the app name: `rtmp(s)?://[^/]+/[^/]+/(.+)` → replace capture group with [REDACTED]
- Query parameters: `(key|token|password|secret|auth|passwd|stream_key|streamkey)=([^&\s]+)` → replace value with [REDACTED]
- URL userinfo: `://([^:]+):([^@]+)@` → replace password with [REDACTED]
- JSON-style key-value: `"(password|stream_key|streamKey|secret|token|auth_key)":\s*"([^"]*)"` → replace value with [REDACTED]

### 2. Create `Utilities/RedactingLogger.swift`

A wrapper around `os.Logger` that ensures sensitive data is never logged.

```swift
import os

/// RedactingLogger wraps Apple's os.Logger to ensure sensitive
/// data like stream keys and passwords are never written to logs.
/// 
/// Usage:
///   let log = RedactingLogger(subsystem: "com.port80.app", category: "streaming")
///   log.info("Connected to server")  // Safe - no secrets
///   log.debug("URL: \(url, privacy: .private)")  // Redacted in release
struct RedactingLogger {
    let logger: Logger

    init(subsystem: String = "com.port80.app", category: String) {
        self.logger = Logger(subsystem: subsystem, category: category)
    }

    // Provide convenience methods: debug, info, warning, error, critical
    // Each should use os.Logger with appropriate privacy annotations
    // In debug builds, log more detail
    // In release builds, minimize logging
}
```

