    /// Whether we should be attempting to reconnect
    private var shouldReconnect: Bool = false

    // Callback to notify engine of connection events
    var onConnectionEvent: ((ConnectionEvent) -> Void)?

    enum ConnectionEvent {
        case connected
        case disconnected(reason: StopReason)
        case reconnecting(attempt: Int, nextRetryMs: Int64)
        case networkAvailable
        case networkUnavailable
    }

    init(reconnectPolicy: ReconnectPolicy = ExponentialBackoffReconnectPolicy()) { ... }

    /// Start monitoring network status
    func startMonitoring() { ... }

    /// Stop monitoring and cancel all reconnects
    func stopMonitoring() { ... }

    /// Begin reconnect sequence after connection loss
    func beginReconnect() { ... }

    /// Cancel all pending reconnect attempts (called on user stop or auth failure)
    func cancelReconnect() { ... }

    /// Handle a connection failure
    func handleConnectionFailure(reason: StopReason) {
        // If auth failure → cancel, never retry
        // If network error → begin reconnect
    }

    deinit {
        stopMonitoring()
    }
}
```

Key behaviors:
1. **NWPathMonitor**: Monitor on a background queue. When `path.status == .satisfied`, if we're in reconnect mode, attempt immediately.
2. **Exponential backoff**: Use `Task.sleep` for delays. Use `Task.isCancelled` to check for cancellation.
3. **Auth failure**: Immediately stop, never retry (wrong credentials won't fix themselves)
4. **User stop**: Cancel the reconnect Task, reset attempt counter
